module.render:
const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;')
  .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
const label = sections[0] ? sections[0].trim() : '';
const txt = label !== '' ? label : 'CONFIDENTIAL';
const variant = (['double', 'solid', 'outline', 'plain'].indexOf(String(args.variant || 'double').toLowerCase()) >= 0)
  ? String(args.variant || 'double').toLowerCase() : 'double';
const color = (args.color && String(args.color).trim()) || 'var(--accent-color)';
const size = (['sm', 'md', 'lg'].indexOf(String(args.size || 'md').toLowerCase()) >= 0) ? String(args.size || 'md').toLowerCase() : 'md';
const upper = String(args.uppercase) === 'true';
const rotRaw = parseFloat(args.rotate);
const rot = Number.isFinite(rotRaw) ? Math.max(-45, Math.min(45, rotRaw)) : 0;
let style = '--stamp-color: ' + color + ';';
if (rot) style += ' transform: rotate(' + rot + 'deg);';
const cls = 'mdp-mod-stamp mdp-stamp--' + variant + (size !== 'md' ? ' st-' + size : '') + (upper ? ' is-upper' : '');
// Inline element (block module + inline render): flows within the header/text.
return '<span class="' + cls + '" style="' + style + '">' + esc(txt) + '</span>';
